import React from 'react';
import { Card, Stack, Heading, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="xl" border={true}>
      <Stack gap={24}>
        {/* Current Weather */}
        <Stack align="center" gap={8}>
          <Heading level={3}>{city}</Heading>
          <Stack direction="horizontal" align="start">
            <Heading level={1}>{temperature}</Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              °{unit}
            </Text>
          </Stack>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Details */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="body" weight="medium">
              {humidity}%
            </Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind Speed
            </Text>
            <Text variant="body" weight="medium">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        {/* 5-Day Forecast */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((f, i) => (
            <Stack key={i} align="center" gap={4} style={{ flex: 1 }}>
              <Text variant="overline">{f.day ?? '-'}</Text>
              <Box>
                <Text size="2xl">{f.icon ?? '☁️'}</Text>
              </Box>
              <Text variant="bodySmall" weight="semibold">
                {f.high ?? 0}° / {f.low ?? 0}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Divider, Spacer } from '@ggui-ai/design/primitives';
import { Input, TextArea, RadioGroup, Checkbox, Button, Heading, Text, Progress } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (answers: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: -1,
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    switch (currentStep) {
      case 1:
        return formData.name.trim() !== '' && validateEmail(formData.email);
      case 2:
        return formData.satisfaction !== -1;
      case 3:
        return formData.features.length > 0;
      case 4:
        return true;
      default:
        return false;
    }
  };

  const handleNext = () => {
    if (currentStep < 4) setCurrentStep(prev => prev + 1);
    else {
      setIsSubmitting(true);
      props.onSubmit(formData);
    }
  };

  const toggleFeature = (f: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(f) ? prev.features.filter(x => x !== f) : [...prev.features, f]
    }));
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={24}>
        <Stack gap={24}>
          <Stack gap={8}>
            <Progress value={currentStep} max={4} variant="default" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Step {currentStep} of 4</Text>
            <Heading level={2}>
              {currentStep === 1 && "Personal Information"}
              {currentStep === 2 && "Satisfaction Rating"}
              {currentStep === 3 && "Feature Interests"}
              {currentStep === 4 && "Review & Submit"}
            </Heading>
          </Stack>

          <Box paddingY={16}>
            {currentStep === 1 && (
              <Stack gap={16}>
                <Input label="Name" required value={formData.name} onChange={(v) => {
                  setFormData(p => ({ ...p, name: v }));
                  setErrors(e => ({ ...e, name: v.trim() ? undefined : 'Name is required' }));
                }} error={errors.name} />
                <Input label="Email" required type="email" value={formData.email} onChange={(v) => {
                  setFormData(p => ({ ...p, email: v }));
                  setErrors(e => ({ ...e, email: validateEmail(v) ? undefined : 'Invalid email format' }));
                }} error={errors.email} />
              </Stack>
            )}

            {currentStep === 2 && (
              <RadioGroup
                label="How satisfied are you with our product?"
                value={formData.satisfaction.toString()}
                onChange={(v) => setFormData(p => ({ ...p, satisfaction: parseInt(v) }))}
                options={props.satisfactionLabels.map((label, i) => ({ value: i.toString(), label }))}
              />
            )}

            {currentStep === 3 && (
              <Stack gap={12}>
                <Text variant="label">Which features are you interested in?</Text>
                {props.featureOptions.map(f => (
                  <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => toggleFeature(f)} />
                ))}
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={16}>
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Satisfaction:</strong> {props.satisfactionLabels[formData.satisfaction]}</Text>
                <Text><strong>Features:</strong> {formData.features.join(', ')}</Text>
                <TextArea label="Comments" value={formData.comments} onChange={(v) => setFormData(p => ({ ...p, comments: v }))} maxLength={500} showCount />
              </Stack>
            )}
          </Box>

          <Divider />

          <Stack direction="horizontal" gap={12} justify="end">
            {currentStep > 1 && (
              <Button variant="ghost" onClick={() => setCurrentStep(prev => prev - 1)}>Back</Button>
            )}
            <Button 
              variant="primary" 
              onClick={handleNext} 
              disabled={!isStepValid() || isSubmitting}
              loading={isSubmitting}
            >
              {currentStep === 4 ? 'Submit Survey' : 'Next'}
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Box, 
  Spacer, 
  Divider 
} from '@ggui-ai/design/primitives';
import { 
  Input, 
  Select, 
  Button, 
  Badge, 
  Avatar 
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Props {
  tasks: Task[];
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasksState, setTasksState] = useState<Task[]>(props.tasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskData, setNewTaskData] = useState<{ title: string; priority: 'low' | 'medium' | 'high' }>({ title: '', priority: 'medium' });

  const totalTasks = tasksState.length;
  const completedTasks = tasksState.filter(t => t.column === 'done').length;

  const handleCreate = (colId: string) => {
    if (!newTaskData.title.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      ...newTaskData,
      column: colId,
      assignee: '??'
    };
    const updated = [...tasksState, newTask];
    setTasksState(updated);
    props.onTaskUpdate?.({ action: 'create', taskId: newTask.id, data: newTask });
    setIsAdding(null);
    setNewTaskData({ title: '', priority: 'medium' });
  };

  const handleMove = (taskId: string, column: string) => {
    setTasksState(prev => prev.map(t => t.id === taskId ? { ...t, column } : t));
    props.onTaskUpdate?.({ action: 'move', taskId, data: { column } });
  };

  const getBadgeVariant = (p?: string): 'error' | 'warning' | 'info' => {
    switch(p) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      default: return 'info';
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Card shadow="sm" padding="var(--ggui-spacing-4)">
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3}>Project Kanban Board</Heading>
          <Text variant="label">Total: {totalTasks} | Completed: {completedTasks}</Text>
        </Stack>
      </Card>

      <Spacer size={24} />

      <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start">
        {props.columns.map((col) => (
          <Box key={col.id} style={{ minWidth: '320px', flex: 1 }} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)" padding="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-4)">
              <Stack direction="horizontal" justify="between" align="center">
                <Heading level={4}>{col.name}</Heading>
                <Badge variant="secondary" size="md">{tasksState.filter(t => t.column === col.id).length}</Badge>
              </Stack>
              <Divider />
              <Stack gap="var(--ggui-spacing-2)">
                {tasksState.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} shadow="sm" radius="md" padding="var(--ggui-spacing-2)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={6}>{task.title}</Heading>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Badge variant={getBadgeVariant(task.priority)} size="sm">{task.priority?.toUpperCase()}</Badge>
                        <Avatar name={task.assignee ?? '??'} size={24} />
                      </Stack>
                      {task.dueDate && <Text variant="caption">Due: {task.dueDate}</Text>}
                      <Select 
                        label="Move to"
                        value={task.column ?? ''} 
                        onChange={(val) => handleMove(task.id!, val)}
                        options={props.columns.map(c => ({ value: c.id!, label: c.name! }))}
                      />
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {isAdding === col.id ? (
                <Card padding="var(--ggui-spacing-4)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Input label="Task Title" value={newTaskData.title} onChange={(val) => setNewTaskData({ ...newTaskData, title: val })} />
                    <Select label="Priority" value={newTaskData.priority} onChange={(val) => setNewTaskData({ ...newTaskData, priority: val as any })} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
                      <Button variant="primary" onClick={() => handleCreate(col.id!)}>Save</Button>
                      <Button variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                    </Stack>
                  </Stack>
                </Card>
              ) : (
                <Button variant="outline" fullWidth onClick={() => setIsAdding(col.id!)}>+ Add Task</Button>
              )}
            </Stack>
          </Box>
        ))}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Box,
  Card,
  Stack,
  Text,
  Heading,
  Input,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-info-100)',
  'nonmetal': 'var(--ggui-color-success-100)',
  'alkali-metal': 'var(--ggui-color-primary-100)',
  'halogen': 'var(--ggui-color-warning-100)',
  'transition-metal': 'var(--ggui-color-container)',
};

const DEFAULT_COLOR = 'var(--ggui-color-surfaceVariant)';

export default function GeneratedComponent(props: Props) {
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const [query, setQuery] = useState('');

  const filtered = useMemo(() => {
    const q = query.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(q) ||
        el.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, query]);

  return (
    <Container maxWidth="3xl" padding="24px">
      <Stack gap="24px">
        <Heading level={2}>Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Search by name or symbol..."
          value={query}
          onChange={(val) => setQuery(val)}
          type="search"
        />

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-2, 8px)',
            minWidth: '900px',
          }}
        >
          {filtered.map((el) => (
            <Box
              key={el.atomicNumber}
              style={{
                gridRow: el.row?.toString(),
                gridColumn: el.col?.toString(),
                padding: 'var(--ggui-spacing-2, 8px)',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                backgroundColor: CATEGORY_COLORS[el.category ?? ''] ?? DEFAULT_COLOR,
                textAlign: 'center',
                border: '1px solid var(--ggui-color-outlineVariant)',
                cursor: 'pointer',
                transition: 'background-color 200ms ease',
              }}
              onClick={() => setSelected(el)}
              role="button"
              tabIndex={0}
              aria-label={`Element ${el.name} (${el.symbol})`}
            >
              <Text variant="caption" style={{ fontSize: '10px' }}>
                {el.atomicNumber}
              </Text>
              <Text weight="bold" as="span" style={{ display: 'block' }}>
                {el.symbol}
              </Text>
            </Box>
          ))}
        </Box>

        {selected && (
          <div aria-live="polite">
            <Card padding="24px" radius="lg">
              <Stack gap="12px">
                <Heading level={3}>
                  {selected.name} ({selected.symbol})
                </Heading>
                <Divider />
                <Stack gap="4px">
                  <Text variant="bodySmall">
                    Atomic Number: {selected.atomicNumber}
                  </Text>
                  <Text variant="bodySmall">
                    Atomic Weight: {selected.atomicWeight}
                  </Text>
                  <Text variant="bodySmall">Category: {selected.category}</Text>
                </Stack>
              </Stack>
            </Card>
          </div>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Box, Text, Heading, Button, Input, Spacer, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function GeneratedComponent(props: Props) {
  const [inputValue, setInputValue] = useState('');
  const [chatMessages, setChatMessages] = useState(props.messages);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setChatMessages(props.messages);
  }, [props.messages]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data && typeof data === 'object') {
        setChatMessages((prev) => [...prev, data]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [chatMessages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const payload = {
      text: inputValue,
      timestamp: new Date().toISOString(),
    };
    setChatMessages((prev) => [...prev, { ...payload, sender: props.currentUser }]);
    setInputValue('');
    window.dispatchEvent(
      new CustomEvent('ggui:action', {
        detail: { actionId: 'sendMessage', payload },
      })
    );
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      padding={0}
      radius="lg"
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '600px',
        width: '100%',
        maxWidth: '500px',
        overflow: 'hidden',
      }}
    >
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" align="center">
          <Heading level={4}>{props.title}</Heading>
          <Spacer size="flex" />
          {props.participantCount !== undefined && (
            <Badge variant="secondary" size="sm">
              {props.participantCount} participants
            </Badge>
          )}
        </Stack>
      </Box>

      <Box padding={16} style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column' }}>
        <div
          ref={scrollContainerRef}
          role="log"
          aria-live="polite"
          style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}
        >
          {chatMessages.map((msg, idx) => {
            const isSelf = msg.sender === props.currentUser;
            const isGrouped = idx > 0 && chatMessages[idx - 1].sender === msg.sender;

            return (
              <Stack key={idx} align={isSelf ? 'end' : 'start'} gap={1}>
                {!isGrouped && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {msg.sender ?? 'Unknown'}
                  </Text>
                )}
                <Box
                  paddingX={12}
                  paddingY={8}
                  borderRadius={8}
                  background={
                    isSelf
                      ? 'var(--ggui-color-primary-600)'
                      : 'var(--ggui-color-surfaceVariant)'
                  }
                >
                  <Text color={isSelf ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}>
                    {msg.text}
                  </Text>
                </Box>
              </Stack>
            );
          })}
        </div>
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              value={inputValue}
              onChange={setInputValue}
              placeholder="Type a message..."
              onKeyDown={handleKeyDown}
            />
          </div>
          <Button
            disabled={!inputValue.trim()}
            onClick={handleSend}
            aria-label="Send message"
            style={{ transition: 'all 200ms ease' }}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Icon,
  Spinner,
} from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: Array<Stock>;
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocksData, setStocksData] = useState<Stock[]>(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const newData = customEvent.detail as Stock[];

      if (Array.isArray(newData)) {
        setStocksData((prev) => {
          const map = new Map(prev.map((s) => [s.symbol, s]));
          newData.forEach((s) => {
            if (s.symbol) {
              map.set(s.symbol, { ...map.get(s.symbol), ...s });
            }
          });
          return Array.from(map.values());
        });
        setLastUpdated(new Date().toISOString());
      }
    };

    document.addEventListener('ggui:agent-data', handleAgentData);
    return () => document.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatChange = (change?: number, percent?: number) => {
    const val = change ?? 0;
    const pct = percent ?? 0;
    const sign = val >= 0 ? '+' : '';
    return `${sign}${Math.abs(val).toFixed(2)} (${sign}${Math.abs(pct).toFixed(2)}%)`;
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        {stocksData.length === 0 ? (
          <Box style={{ display: 'flex', justifyContent: 'center', padding: 'var(--ggui-spacing-12, 48px)' }}>
            <Spinner size={48} />
          </Box>
        ) : (
          <Box
            style={{
              display: 'grid',
              gap: 'var(--ggui-spacing-4, 16px)',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            }}
          >
            {stocksData.map((stock, i) => {
              const changeVal = stock.change ?? 0;
              const isPositive = changeVal >= 0;
              const color = isPositive
                ? 'var(--ggui-color-success, #16a34a)'
                : 'var(--ggui-color-error, #dc2626)';

              return (
                <Card
                  key={stock.symbol ?? i}
                  shadow="sm"
                  border={true}
                  radius="lg"
                  padding="var(--ggui-spacing-4, 16px)"
                  style={{ borderLeft: `4px solid ${color}` }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text weight="bold" size="xl">{stock.symbol ?? 'N/A'}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name}
                      </Text>
                    </Stack>

                    <Box aria-live="polite">
                      <Text size="3xl" weight="bold">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                    </Box>

                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-1, 4px)">
                      <Icon
                        name={isPositive ? 'chevron-up' : 'chevron-down'}
                        size={16}
                        color={color}
                      />
                      <Text color={color} weight="medium">
                        {formatChange(stock.change, stock.changePercent)}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Divider, 
  Text, 
  Heading,
  Spacer
} from '@ggui-ai/design/primitives';
import { 
  Button, 
  Progress,
  Input,
  Select,
  Toggle,
  RadioGroup,
  MotionKeyframes 
} from '@ggui-ai/design/components';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  useEffect(() => {
    const handleAgentData = (e: any) => console.log('Agent Data Received:', e.detail);
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const validateStep = (step: number) => {
    if (step === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return formData.name.trim() !== '' && emailRegex.test(formData.email);
    }
    return true;
  };

  const isStepValid = validateStep(currentStep);

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 3
          </Text>
          <Progress 
            value={(currentStep / 3) * 100} 
            max={100} 
            variant="default" 
            size="md" 
          />
        </Stack>

        <Card padding="var(--ggui-spacing-6, 24px)" radius="lg">
          {currentStep === 1 && (
            <Stack gap={16}>
              <Heading level={2}>Profile Setup</Heading>
              <Input label="Name" required value={formData.name} onChange={(v) => setFormData(f => ({...f, name: v}))} />
              <Input label="Email" required type="email" value={formData.email} onChange={(v) => setFormData(f => ({...f, email: v}))} />
              <RadioGroup 
                label="Select Avatar" 
                value={formData.avatar} 
                onChange={(v) => setFormData(f => ({...f, avatar: v}))} 
                options={props.avatarOptions.map(a => ({ value: a, label: a }))} 
                direction="horizontal" 
              />
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap={16}>
              <Heading level={2}>Preferences</Heading>
              <Select 
                label="Role"
                value={formData.role} 
                onChange={(v) => setFormData(f => ({...f, role: v}))} 
                options={props.roleOptions.map(r => ({ value: r, label: r }))} 
              />
              <Toggle 
                label="Email Notifications" 
                checked={formData.emailNotifications} 
                onChange={(v) => setFormData(f => ({...f, emailNotifications: v}))} 
              />
              <Select 
                label="Theme"
                value={formData.theme} 
                onChange={(v) => setFormData(f => ({...f, theme: v}))} 
                options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} 
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap={16}>
              <Heading level={2}>Review & Confirm</Heading>
              <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                <Stack gap={8}>
                  <Text><strong>Name:</strong> {formData.name}</Text>
                  <Text><strong>Email:</strong> {formData.email}</Text>
                  <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                  <Text><strong>Role:</strong> {formData.role}</Text>
                  <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  <Text><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Box>
            </Stack>
          )}

          <Divider margin="24px 0" />

          <Stack direction="horizontal" gap={16} justify="between">
            <Button variant="ghost" onClick={() => setCurrentStep(p => p - 1)} disabled={currentStep === 1}>Back</Button>
            {currentStep < 3 ? (
              <Button variant="primary" onClick={() => setCurrentStep(p => p + 1)} disabled={!isStepValid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => props.onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
